public class Main {

    static int gcd(int a, int b) {
        while (b != 0) {
            int temp = b;
            b = a % b;
            a = temp;
        }
        return a;
    }

    static int lcm(int a, int b) {
        return (a * b) / gcd(a, b);
    }

    public static void main(String[] args) {
        int num1 = 48, num2 = 18;

        System.out.println("Sayilar: " + num1 + " ve " + num2);
        System.out.println("EBOB (GCD): " + gcd(num1, num2));
        System.out.println("EKOK (LCM): " + lcm(num1, num2));

        // Birden fazla cift icin tablo
        System.out.println("\nFarkli sayi ciftleri:");
        int[][] pairs = {{12, 18}, {7, 13}, {100, 75}, {24, 36}};

        for (int[] pair : pairs) {
            int a = pair[0];
            int b = pair[1];
            System.out.println("GCD(" + a + "," + b + ") = " + gcd(a, b) +
                               ", LCM(" + a + "," + b + ") = " + lcm(a, b));
        }
    }
}
